from openai import OpenAI
client = OpenAI()

response = client.chat.completions.create(
    model='gpt-4o',
    messages=[
        # Director's script — runs before any user message
        {
            'role': 'system',
            'content': 'You are a concise customer support agent for Acme Corp. '
                       'Answer only questions about Acme products. '
                       'If the question is off-topic, say: I can only help with Acme products.',
        },
        # User's turn
        {
            'role': 'user',
            'content': 'How do I reset my Acme SmartLock password?',
        },
    ],
)
print(response.choices[0].message.content)

oa_questions.answer:
User role. The document is input to be processed, not developer-set instructions. Put the document content in the user message (e.g., 'Document:
{pdf_text}

Question: {question}'). System is for developer-controlled rules (persona, constraints) that apply across all requests.
